import { forwardRef } from "react";
import PropTypes from "prop-types";
import "./HamburgerToggle.scss";

const HamburgerToggle = forwardRef(function HamburgerToggle(
  { isOpen, toggleMenu },
  ref
) {
  return (
    <button
      ref={ref}
      type="button"
      className={`menu__toggle ${isOpen ? "is-open" : ""}`}
      aria-expanded={isOpen}
      aria-controls="mobile-navigation"
      aria-haspopup="dialog"
      aria-label={isOpen ? "Close menu" : "Open menu"}
      onClick={toggleMenu}
    >
      <span className="menu__toggle-label">{isOpen ? "Close" : "Menu"}</span>

      <span className="menu__toggle-icon" aria-hidden="true">
        <span></span>
        <span></span>
        <span></span>
      </span>
    </button>
  );
});

HamburgerToggle.propTypes = {
  isOpen: PropTypes.bool.isRequired,
  toggleMenu: PropTypes.func.isRequired,
};

export default HamburgerToggle;
