import React from "react";
import PropTypes from "prop-types";
import { Link } from "react-router-dom";
import { getResponsiveImageProps } from "../../utils/responsiveImages";
import "./Excursions.scss";

// Import data
import { EXCURSIONS_DATA } from "../../assets/data/excursionsData";
// Import hook
import { useAnimateOnScroll } from "../../hooks/useAnimateOnScroll";

const EXCURSION_SIGNALS = [
  "Balanced half-day and full-day pacing",
  "Easy to pair with your hotel stay",
  "Good first picks for a Zanzibar trip",
];

/**
 * Reusable Arrow Icon Component
 * Used in card links and "View More" button
 */
const ArrowIcon = () => (
  <svg
    fill="none"
    viewBox="0 0 24 24"
    strokeWidth="1.5"
    stroke="currentColor"
    aria-hidden="true"
  >
    <path
      strokeLinecap="round"
      strokeLinejoin="round"
      d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3"
    />
  </svg>
);

/**
 * ExcursionCard Component
 * Displays individual excursion with image, badge, and details
 */
const ExcursionCard = ({ trip, index }) => {
  const [cardRef, isVisible] = useAnimateOnScroll({ threshold: 0.1 });
  const cardVariant = index === 0 ? "excursion-card--featured" : "excursion-card--standard";
  const responsiveImageProps = getResponsiveImageProps(
    trip.image,
    "(min-width: 1024px) 32vw, (min-width: 768px) 46vw, 92vw",
    { sm: 640, lg: 960 }
  );

  return (
    <article
      ref={cardRef}
      className={`excursion-card ${cardVariant} ${isVisible ? "animate" : ""}`}
      style={{ 
        transitionDelay: `${index * 0.1}s` 
      }}
    >
      <div className="excursion-card__image-wrapper">
        <img
          src={trip.image}
          alt={trip.title}
          className="excursion-card__image"
          loading="lazy"
          decoding="async"
          {...responsiveImageProps}
        />
        {trip.duration && (
          <span 
            className="excursion-card__badge"
            aria-label={`Duration: ${trip.duration}`}
          >
            {trip.duration}
          </span>
        )}
      </div>

      <div className="excursion-card__content">
        <div className="excursion-card__meta">
          <span className="excursion-card__index">
            {String(index + 1).padStart(2, "0")}
          </span>
        </div>
        <h3 className="excursion-card__title">{trip.title}</h3>
        <p className="excursion-card__text">{trip.description}</p>
        <Link
          to={`/excursions/${trip.id}`}
          className="excursion-card__link"
          aria-label={`Learn more about ${trip.title}`}
        >
          {trip.linkText}
          <ArrowIcon />
        </Link>
      </div>
    </article>
  );
};

ExcursionCard.propTypes = {
  trip: PropTypes.shape({
    id: PropTypes.string.isRequired,
    title: PropTypes.string.isRequired,
    description: PropTypes.string.isRequired,
    image: PropTypes.string.isRequired,
    linkText: PropTypes.string.isRequired,
    duration: PropTypes.string,
  }).isRequired,
  index: PropTypes.number.isRequired,
};

/**
 * Excursions Component
 * Main section displaying featured excursions grid
 */
const Excursions = () => {
  const [sectionRef, isVisible] = useAnimateOnScroll({ 
    threshold: 0.1,
    rootMargin: '50px'
  });

  // Handle empty data gracefully
  if (!EXCURSIONS_DATA || EXCURSIONS_DATA.length === 0) {
    return null;
  }

  return (
    <section
      ref={sectionRef}
      className={`excursions ${isVisible ? "animate" : ""}`}
    >
      <div className="excursions__intro">
        <div className="excursions__heading">
          <p className="excursions__eyebrow">Featured island days</p>
          <h2 className="excursions__title">Roaming Retreats</h2>
        </div>
        <p className="excursions__description">
          Start with the experiences guests fall for first: slow cultural walks, iconic dhow days,
          and sensory Zanzibar adventures that layer naturally into a memorable stay.
        </p>
      </div>
      <div className="excursions__signals" aria-label="Section highlights">
        {EXCURSION_SIGNALS.map((signal) => (
          <span key={signal}>{signal}</span>
        ))}
      </div>
      <div className="excursions__grid">
        {EXCURSIONS_DATA.map((trip, index) => (
          <ExcursionCard key={trip.id} trip={trip} index={index} />
        ))}
      </div>
      <div 
        className="excursions__more"
        style={{ 
          transitionDelay: `${EXCURSIONS_DATA.length * 0.1}s` 
        }}
      >
        <Link to="/excursions" className="excursions__more-link">
          <span>View More Excursions</span>
          <ArrowIcon />
          <span className="sr-only">View all available excursions</span>
        </Link>
      </div>
    </section>
  );
};

export default Excursions;
