const OPTIMIZED_SEGMENT = "/optimized/";

export const getOptimizedVariantPath = (src, variant = "sm") => {
  if (!src.includes(OPTIMIZED_SEGMENT)) {
    return src;
  }

  return src.replace(OPTIMIZED_SEGMENT, `/optimized-${variant}/`);
};

export const getResponsiveImageProps = (
  src,
  sizes,
  widths = { sm: 640, lg: 960 }
) => {
  if (!src.includes(OPTIMIZED_SEGMENT)) {
    return {};
  }

  return {
    srcSet: `${getOptimizedVariantPath(src, "sm")} ${widths.sm}w, ${src} ${widths.lg}w`,
    sizes,
  };
};
