import { Link } from "react-router-dom";
import './Hero.scss';
import backgroundVideoH from '../../assets/videos/background_h_optimized.mp4';
import backgroundVideoV from '../../assets/videos/background_v_optimized.mp4';
import { useEffect, useRef, useState } from 'react';
import { getOptimizedVariantPath } from "../../utils/responsiveImages";

const MOBILE_MEDIA = '(max-width: 767px)';

const HERO_HIGHLIGHTS = [
  "Private island itineraries",
  "Hotel pick-up planning",
  "Local guides and smooth support",
];

const HERO_STATS = [
  { value: "Tailored", label: "experiences shaped around your stay" },
  { value: "Local", label: "knowledge from Zanzibar-based hosts" },
  { value: "Easy", label: "booking help before and during your trip" },
];

const HERO_ROUTE = [
  { stop: "Stone Town", note: "easy arrival pacing" },
  { stop: "Ocean Days", note: "private sea and sandbar time" },
  { stop: "Sunset Finish", note: "a dhow evening to close it out" },
];

const Hero = () => {
  const videoRef = useRef(null);
  const [videoLoaded, setVideoLoaded] = useState(false);
  const [isMobile, setIsMobile] = useState(
    () => typeof window !== 'undefined' && window.matchMedia(MOBILE_MEDIA).matches
  );
  const videoSrc = isMobile ? backgroundVideoV : backgroundVideoH;
  const posterSrc = isMobile
    ? getOptimizedVariantPath("/images/optimized/boat.jpg", "sm")
    : "/images/optimized/boat.jpg";

  useEffect(() => {
    const mql = window.matchMedia(MOBILE_MEDIA);
    const handleChange = (event) => setIsMobile(event.matches);
    mql.addEventListener('change', handleChange);

    return () => {
      mql.removeEventListener('change', handleChange);
    };
  }, []);

  useEffect(() => {
    const videoElement = videoRef.current;

    if (!videoElement) {
      return;
    }

    const handleVideoLoad = () => setVideoLoaded(true);

    setVideoLoaded(videoElement.readyState >= 2);
    videoElement.addEventListener('loadeddata', handleVideoLoad);

    return () => {
      videoElement.removeEventListener('loadeddata', handleVideoLoad);
    };
  }, [videoSrc]);

  return (
    <section className="hero">
      <div className="hero__background" aria-hidden="true">
        <video
          key={videoSrc}
          ref={videoRef}
          autoPlay
          loop
          muted
          playsInline
          preload="metadata"
          poster={posterSrc}
          className={`hero__video ${videoLoaded ? 'visible' : ''}`}
        >
          <source src={videoSrc} type="video/mp4" />
        </video>
      </div>
      <div className="hero__veil" aria-hidden="true" />
      <div className="hero__content">
        <div className="hero__copy">
          <p className="hero__eyebrow">Private tours and island escapes in Zanzibar</p>
          <HeroHeading />
          <HeroDescription />
          <div className="hero__actions">
            <Link to="/booking" className="hero__button hero__button--primary">
              Start Planning
            </Link>
            <Link to="/excursions" className="hero__button hero__button--secondary">
              Explore Excursions
            </Link>
          </div>
          <div className="hero__microcopy" aria-label="Planning benefits">
            <span>Fast replies</span>
            <span>Zanzibar-based support</span>
            <span>Tailored from your hotel</span>
          </div>
          <ul className="hero__highlights" aria-label="Why choose Destination Paradise">
            {HERO_HIGHLIGHTS.map((item, index) => (
              <li key={item}>
                <span className="hero__highlight-index">
                  {String(index + 1).padStart(2, "0")}
                </span>
                <span className="hero__highlight-text">{item}</span>
              </li>
            ))}
          </ul>
        </div>
        <aside className="hero__panel">
          <p className="hero__panel-kicker">Island blueprint</p>
          <p className="hero__panel-eyebrow">Designed around your stay</p>
          <h2 className="hero__panel-title">
            Dhow sunsets, spice trails, cave swims, and safari add-ons coordinated with a calm local touch.
          </h2>
          <div className="hero__route" aria-label="Sample itinerary rhythm">
            {HERO_ROUTE.map((item) => (
              <div className="hero__route-step" key={item.stop}>
                <span className="hero__route-stop">{item.stop}</span>
                <span className="hero__route-note">{item.note}</span>
              </div>
            ))}
          </div>
          <div className="hero__stats">
            {HERO_STATS.map((stat) => (
              <div key={stat.value} className="hero__stat">
                <span className="hero__stat-value">{stat.value}</span>
                <span className="hero__stat-label">{stat.label}</span>
              </div>
            ))}
          </div>
        </aside>
      </div>
    </section>
  );
};

const HeroHeading = () => (
  <div className="hero__heading">
    <h1>Destination Paradise</h1>
    <p className="motto">Your next trip to paradise, shaped with local insight and a little more wonder.</p>
  </div>
);

const HeroDescription = () => (
  <p className="hero__description">
    Trade generic travel days for curated island moments, from heritage walks and blue-water adventures
    to one-of-a-kind experiences that feel personal from the very first message.
  </p>
);

export default Hero;
