import { Link } from "react-router-dom";
import PropTypes from "prop-types";
import scrollToTop from "../../../utils/scrollToTop";
import logo from "../../../assets/logo/dlp-nav.png";
import "./LogoLink.scss";

const LogoLink = ({ className = "", onClick = () => {}, variant = "nav" }) => {
  const classes = ["menu__logo", `menu__logo--${variant}`, className]
    .filter(Boolean)
    .join(" ");

  return (
    <Link
      to="/"
      className={classes}
      aria-label="Destination Paradise Zanzibar, Tanzania"
      onClick={() => {
        onClick();
        scrollToTop();
      }}
    >
      <span className="menu__logo-mark">
        <img src={logo} alt="" width="128" height="128" decoding="async" />
      </span>
      <span className="menu__logo-copy">
        <span className="menu__logo-name">Destination Paradise</span>
        <span className="menu__logo-tag">Zanzibar, Tanzania</span>
      </span>
    </Link>
  );
};

LogoLink.propTypes = {
  className: PropTypes.string,
  onClick: PropTypes.func,
  variant: PropTypes.oneOf(["nav", "drawer"]),
};

export default LogoLink;
