import { lazy, Suspense, useEffect, useRef, useState } from "react";
import "./Home.scss";
import Hero from './Hero.jsx';
import Excursions from './Excursions.jsx';
import UniqueExperiences from "../unique/sections/UniqueExperiences";
import Images from './Images.jsx';

const Testimonials = lazy(() => import("./Testimonials.jsx"));
const MyMap = lazy(() => import("./MyMap.jsx"));

const DeferredSection = ({
    children,
    minHeight = 0,
    rootMargin = "320px 0px",
}) => {
    const sectionRef = useRef(null);
    const [shouldRender, setShouldRender] = useState(false);

    useEffect(() => {
        const element = sectionRef.current;

        if (!element || shouldRender) {
            return undefined;
        }

        const observer = new IntersectionObserver(
            ([entry]) => {
                if (entry.isIntersecting) {
                    setShouldRender(true);
                    observer.unobserve(entry.target);
                }
            },
            {
                rootMargin,
                threshold: 0.01,
            }
        );

        observer.observe(element);

        return () => {
            observer.disconnect();
        };
    }, [rootMargin, shouldRender]);

    return (
        <div ref={sectionRef} style={shouldRender ? undefined : { minHeight }}>
            {shouldRender ? children : null}
        </div>
    );
};

function Home() {
    return (
        <div className='home-container'>
            <Hero />
            <main className="home-container__content">
                <Excursions />
                <UniqueExperiences />
                <Images />
                <DeferredSection minHeight="42rem">
                    <Suspense fallback={null}>
                        <Testimonials />
                    </Suspense>
                </DeferredSection>
                <DeferredSection minHeight="36rem">
                    <Suspense fallback={null}>
                        <MyMap />
                    </Suspense>
                </DeferredSection>
            </main>
        </div>
    );
}

export default Home;
