import { Link, useLocation } from "react-router-dom";
import PropTypes from "prop-types";
import scrollToTop from "../../../utils/scrollToTop";
import "./MenuList.scss";

const menuItems = [
  { label: "Home", path: "/" },
  { label: "Excursions", path: "/excursions" },
  { label: "About Us", path: "/aboutus" },
  { label: "Gallery", path: "/gallery" },
  { label: "Booking Request", path: "/booking" },
];

const MenuList = ({ onNavigate, variant }) => {
  const location = useLocation();

  return (
    <ul className={`menu-list menu-list--${variant}`}>
      {menuItems.map(({ label, path }) => {
        const isActive =
          path === "/"
            ? location.pathname === path
            : location.pathname.startsWith(path);

        return (
          <li className="menu-list__item" key={label}>
            <Link
              className={`menu-list__link ${isActive ? "is-active" : ""}`}
              aria-current={isActive ? "page" : undefined}
              to={path}
              onClick={() => {
                onNavigate();
                scrollToTop();
              }}
            >
              <span className="menu-list__text">{label}</span>
            </Link>
          </li>
        );
      })}
    </ul>
  );
};

MenuList.propTypes = {
  onNavigate: PropTypes.func.isRequired,
  variant: PropTypes.oneOf(["desktop", "mobile"]).isRequired,
};

export default MenuList;
