import "./Footer.scss";

import NewsletterForm from "./components/NewsletterForm";
import ContactInfo from "./components/ContactInfo";
import SocialLinks from "./components/SocialLinks";
import LegalSection from "./components/LegalSection";
import { useIntersectionObserver } from "../../hooks/useIntersectionObserver";

function Footer() {
  const [footerRef, footerEntries] = useIntersectionObserver({ threshold: 0.1 });
  const isVisible = footerEntries.some((entry) => entry.isIntersecting);

  return (
    <footer
      ref={footerRef}
      className={`footer ${isVisible ? "is-visible" : ""}`}
    >
      <div className="footer__container">
        <div className="footer__intro">
          <p className="footer__eyebrow">Destination Paradise</p>
          <h2 className="footer__title">
            End the scroll with something worth planning.
          </h2>
          <p className="footer__description">
            Stay close to new Zanzibar ideas, relaxed travel notes, and the kind of
            local updates that make trip planning feel easier.
          </p>
        </div>

        <div className="footer__grid-area footer__grid-area--newsletter">
          <h3 className="footer__section-title">Get occasional island notes</h3>
          <p className="footer__section-copy">
            A light-touch newsletter with fresh experiences, seasonal highlights,
            and booking inspiration.
          </p>
          <NewsletterForm />
        </div>

        <div className="footer__grid-area footer__grid-area--contact">
          <h4 className="footer__section-title">Plan with us</h4>
          <p className="footer__section-copy">
            Reach out for bookings, questions, or help shaping the right island mix.
          </p>
          <ContactInfo />
        </div>

        <div className="footer__grid-area footer__grid-area--social">
          <h4 className="footer__section-title">Follow the mood</h4>
          <p className="footer__section-copy">
            Find more behind-the-scenes moments, sea days, and Zanzibar snapshots.
          </p>
          <SocialLinks />
        </div>

        <div className="footer__bottom">
          <LegalSection />
          <div className="footer__copyright">
            <p>
            &copy; {new Date().getFullYear()} Destination Paradise. All rights
            reserved.
            </p>
          </div>
        </div>
      </div>
    </footer>
  );
}

export default Footer;
