import PropTypes from "prop-types";
import { Link } from "react-router-dom";
import { useAnimateOnScroll } from "../../../hooks/useAnimateOnScroll";
import Slideshow from "../sections/Slideshow";
import ArrowIcon from "./ArrowIcon";
import "./ExperienceCard.scss";

const ExperienceCard = ({ trip, index }) => {
  const [cardRef, isVisible] = useAnimateOnScroll({ threshold: 0.1 });

  const getDestination = (id, title) => {
    if (id === "dream-dhow-cruise") {
      return { to: "/dream-dhow" };
    }

    return {
      to: "/booking",
      state: {
        selectedTour: title,
      },
    };
  };

  const destination = getDestination(trip.id, trip.title);

  return (
    <article
      ref={cardRef}
      className={`experience-card ${isVisible ? "animate" : ""}`}
      style={{ transitionDelay: `${index * 0.1}s` }}
    >
      <div className="experience-card__media">
        {trip.images ? (
          <Slideshow images={trip.images} title={trip.title} />
        ) : (
          <img
            src={trip.image}
            alt={trip.title}
            className="experience-card__image"
            loading="lazy"
            decoding="async"
          />
        )}
      </div>

      <div className="experience-card__content">
        <div className="experience-card__meta">
          <span className="experience-card__index">
            {String(index + 1).padStart(2, "0")}
          </span>
        </div>
        <h3 className="experience-card__title reveal">{trip.title}</h3>
        <p className="experience-card__text reveal">{trip.description}</p>
        <Link
          to={destination.to}
          state={destination.state}
          className="experience-card__link"
          aria-label={`Learn more about ${trip.title}`}
        >
          {trip.linkText}
          <ArrowIcon />
        </Link>
      </div>
    </article>
  );
};

ExperienceCard.propTypes = {
  trip: PropTypes.shape({
    id: PropTypes.string.isRequired,
    title: PropTypes.string.isRequired,
    description: PropTypes.string.isRequired,
    image: PropTypes.string,
    images: PropTypes.arrayOf(PropTypes.string),
    linkText: PropTypes.string.isRequired,
  }).isRequired,
  index: PropTypes.number.isRequired,
};

export default ExperienceCard;
