import { Link } from "react-router-dom";
import PropTypes from "prop-types";
import { useAnimateOnScroll } from "../../hooks/useAnimateOnScroll";
import { getResponsiveImageProps } from "../../utils/responsiveImages";
import "./Images.scss";

const SECTION_OBSERVER_OPTIONS = {
  threshold: 0.12,
  rootMargin: "80px 0px",
};

const GALLERY_VARIANTS = [
  "gallery__card--feature",
  "gallery__card--feature-secondary",
  "gallery__card--standard",
  "gallery__card--standard",
  "gallery__card--standard",
  "gallery__card--panorama",
];

const GALLERY_ITEMS = [
  {
    id: "stonetown",
    kind: "image",
    title: "Stone Town textures",
    note: "Doorways, coral stone, and the slower details that shape the island.",
    image: "/galleryimages/optimized/stonetown.jpg",
    to: "/gallery",
  },
  {
    id: "safari-blue",
    kind: "video",
    title: "Safari Blue at sea",
    note: "A quick look at dhow sailing, sandbanks, and bright Indian Ocean water.",
    image: "/galleryimages/optimized/safariblue.jpg",
    href: "https://www.youtube.com/watch?v=iq-NDeo_33k",
  },
  {
    id: "prison-island",
    kind: "image",
    title: "Prison Island scenes",
    note: "Historic shoreline views and one of the easiest island add-ons to love.",
    image: "/galleryimages/optimized/prison.jpg",
    to: "/gallery",
  },
  {
    id: "mnemba",
    kind: "video",
    title: "Mnemba snorkeling day",
    note: "Boat rides, reef color, and the kind of water that sells the whole trip.",
    image: "/galleryimages/optimized/mnemba.jpg",
    href: "https://www.youtube.com/watch?v=qYBauN6rzfI",
  },
  {
    id: "spice-tour",
    kind: "image",
    title: "Spice trail colors",
    note: "A softer inland side of Zanzibar that balances the coast beautifully.",
    image: "/galleryimages/optimized/spice-tour.jpg",
    to: "/gallery",
  },
  {
    id: "island-moments",
    kind: "image",
    title: "More island moments",
    note: "A broader sweep of beaches, villages, and little in-between memories.",
    image: "/galleryimages/optimized/26.jpg",
    to: "/gallery",
  },
];

const ArrowIcon = () => (
  <svg
    fill="none"
    viewBox="0 0 24 24"
    strokeWidth="1.5"
    stroke="currentColor"
    aria-hidden="true"
  >
    <path
      strokeLinecap="round"
      strokeLinejoin="round"
      d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3"
    />
  </svg>
);

const PlayIcon = () => (
  <svg
    fill="currentColor"
    viewBox="0 0 24 24"
    aria-hidden="true"
  >
    <path d="M8.5 6.75v10.5L17 12 8.5 6.75Z" />
  </svg>
);

const GalleryCardContent = ({ item }) => {
  const responsiveImageProps = getResponsiveImageProps(
    item.image,
    "(min-width: 1200px) 24vw, (min-width: 768px) 31vw, 92vw",
    { sm: 560, lg: 900 }
  );

  return (
    <>
      <div className="gallery__card-media">
        <img
          src={item.image}
          alt={item.title}
          className="gallery__card-image"
          loading="lazy"
          decoding="async"
          {...responsiveImageProps}
        />
        <div className="gallery__card-scrim" aria-hidden="true" />
        {item.kind === "video" && (
          <span className="gallery__play" aria-hidden="true">
            <PlayIcon />
          </span>
        )}
      </div>
      <div className="gallery__card-meta">
        <span className="gallery__tag">
          {item.kind === "video" ? "Video story" : "Photo moment"}
        </span>
        <h3 className="gallery__card-title">{item.title}</h3>
        <p className="gallery__card-note">{item.note}</p>
        <span className="gallery__card-action">
          {item.kind === "video" ? "Watch story" : "Open gallery"}
          <ArrowIcon />
        </span>
      </div>
    </>
  );
};

GalleryCardContent.propTypes = {
  item: PropTypes.shape({
    kind: PropTypes.oneOf(["image", "video"]).isRequired,
    image: PropTypes.string.isRequired,
    note: PropTypes.string.isRequired,
    title: PropTypes.string.isRequired,
  }).isRequired,
};

const GalleryCard = ({ item, index, isVisible }) => {
  const className = [
    "gallery__card",
    GALLERY_VARIANTS[index] || "gallery__card--standard",
    isVisible ? "animate" : "",
  ]
    .filter(Boolean)
    .join(" ");
  const style = { transitionDelay: `${index * 0.08}s` };

  if (item.href) {
    return (
      <a
        href={item.href}
        target="_blank"
        rel="noreferrer"
        className={className}
        style={style}
        aria-label={`${item.title} video opens in a new tab`}
      >
        <GalleryCardContent item={item} />
      </a>
    );
  }

  return (
    <Link to={item.to} className={className} style={style}>
      <GalleryCardContent item={item} />
    </Link>
  );
};

GalleryCard.propTypes = {
  index: PropTypes.number.isRequired,
  isVisible: PropTypes.bool.isRequired,
  item: PropTypes.shape({
    href: PropTypes.string,
    id: PropTypes.string.isRequired,
    image: PropTypes.string.isRequired,
    kind: PropTypes.oneOf(["image", "video"]).isRequired,
    note: PropTypes.string.isRequired,
    title: PropTypes.string.isRequired,
    to: PropTypes.string,
  }).isRequired,
};

const Images = () => {
  const [sectionRef, isVisible] = useAnimateOnScroll(SECTION_OBSERVER_OPTIONS);

  return (
    <section
      ref={sectionRef}
      className={`images-gallery ${isVisible ? "animate" : ""}`}
    >
      <div className="gallery__intro">
        <div className="gallery__heading">
          <p className="gallery__eyebrow">Island moodboard</p>
          <h2 className="gallery__title">A glimpse of the island</h2>
        </div>
        <p className="gallery__description">
          A quick visual sweep through the coastlines, textures, and blue-water
          days that give Destination Paradise its rhythm.
        </p>
      </div>

      <div className="gallery-grid">
        {GALLERY_ITEMS.map((item, index) => (
          <GalleryCard
            key={item.id}
            item={item}
            index={index}
            isVisible={isVisible}
          />
        ))}
      </div>

      <div className="gallery__more">
        <Link to="/gallery" className="gallery__more-link">
          <span>View full gallery</span>
          <ArrowIcon />
        </Link>
      </div>
    </section>
  );
};

export default Images;
