import { useState, useEffect, useCallback, useRef } from "react";
import ClassicMenu from "./components/ClassicMenu";
import StoreButton from "./components/StoreButton";
import LogoLink from "./components/LogoLink";
import HamburgerToggle from "./components/HamburgerToggle";
import HamburgerMenuBox from "./components/HamburgerMenuBox";
import "./NavBar.scss";

const NavBar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const toggleButtonRef = useRef(null);
  const wasOpenRef = useRef(false);

  const toggleMenu = useCallback(() => {
    setIsOpen((prev) => !prev);
  }, []);

  const closeMenu = useCallback(() => {
    setIsOpen(false);
  }, []);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 10);
    };

    window.addEventListener("scroll", handleScroll, { passive: true });
    handleScroll();

    return () => {
      window.removeEventListener("scroll", handleScroll);
    };
  }, []);

  useEffect(() => {
    const shouldLockScroll = isOpen && window.innerWidth < 1024;

    if (shouldLockScroll) {
      document.body.style.overflow = "hidden";
      document.documentElement.style.overflow = "hidden";
    } else {
      document.body.style.overflow = "";
      document.documentElement.style.overflow = "";
    }

    return () => {
      document.body.style.overflow = "";
      document.documentElement.style.overflow = "";
    };
  }, [isOpen]);

  useEffect(() => {
    if (isOpen) {
      requestAnimationFrame(() => {
        const firstMenuItem = document.querySelector(
          ".mobile-menu .menu-list--mobile .menu-list__link"
        );
        firstMenuItem?.focus();
      });
    } else if (wasOpenRef.current) {
      toggleButtonRef.current?.focus();
    }

    wasOpenRef.current = isOpen;
  }, [isOpen]);

  useEffect(() => {
    if (!isOpen) {
      return undefined;
    }

    const handleEscape = (event) => {
      if (event.key === "Escape") {
        closeMenu();
      }
    };

    document.addEventListener("keydown", handleEscape);

    return () => {
      document.removeEventListener("keydown", handleEscape);
    };
  }, [isOpen, closeMenu]);

  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth >= 1024) {
        document.body.style.overflow = "";
        document.documentElement.style.overflow = "";
        setIsOpen(false);
      }
    };

    window.addEventListener("resize", handleResize, { passive: true });

    return () => {
      window.removeEventListener("resize", handleResize);
    };
  }, []);

  return (
    <div className={`navbar-wrapper ${isOpen ? "menu-open" : ""}`}>
      <nav
        className={`nav ${isScrolled ? "scrolled" : ""} ${isOpen ? "menu-open" : ""}`}
        aria-label="Main navigation"
      >
        <div className="nav__brand">
          <LogoLink onClick={closeMenu} />
        </div>

        <ClassicMenu onNavigate={closeMenu} />

        <div className="nav__actions">
          <div className="nav__desktop-cta">
            <StoreButton onClick={closeMenu} variant="desktop" />
          </div>

          <div className="nav__mobile-toggle">
            <HamburgerToggle
              ref={toggleButtonRef}
              isOpen={isOpen}
              toggleMenu={toggleMenu}
            />
          </div>
        </div>
      </nav>

      {isOpen ? <HamburgerMenuBox isOpen={isOpen} closeMenu={closeMenu} /> : null}
    </div>
  );
};

export default NavBar;
