import { Link } from "react-router-dom";
import PropTypes from "prop-types";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import { faCompass } from "@fortawesome/free-solid-svg-icons";
import "./StoreButton.scss";

const StoreButton = ({ onClick, variant = "desktop" }) => (
  <Link
    to="/booking"
    className={`store-button store-button--${variant}`}
    onClick={onClick}
    aria-label="Plan your trip"
  >
    <FontAwesomeIcon
      className="store-button__icon"
      icon={faCompass}
      aria-hidden="true"
    />
    <span className="store-button__label">Plan Your Trip</span>
  </Link>
);

StoreButton.propTypes = {
  onClick: PropTypes.func.isRequired,
  variant: PropTypes.oneOf(["desktop", "drawer"]),
};

export default StoreButton;
