let revealObserver;
let revealMutationObserver;
const observedReveals = new WeakSet();

function addRevealObserver() {
  if (revealObserver || typeof window === "undefined") {
    return revealObserver;
  }

  if (!("IntersectionObserver" in window)) {
    return null;
  }

  revealObserver = new IntersectionObserver(
    (entries) => {
      entries.forEach((entry) => {
        if (entry.isIntersecting) {
          entry.target.classList.add("active");
          revealObserver?.unobserve(entry.target);
        }
      });
    },
    {
      threshold: 0.12,
      rootMargin: "0px 0px -80px 0px",
    }
  );

  return revealObserver;
}

function observeRevealElement(element) {
  if (!(element instanceof HTMLElement) || observedReveals.has(element)) {
    return;
  }

  const observer = addRevealObserver();

  if (!observer) {
    element.classList.add("active");
    observedReveals.add(element);
    return;
  }

  observedReveals.add(element);
  observer.observe(element);
}

function scanForRevealElements(root) {
  if (!root) {
    return;
  }

  if (root instanceof HTMLElement && root.classList.contains("reveal")) {
    observeRevealElement(root);
  }

  if ("querySelectorAll" in root) {
    root.querySelectorAll(".reveal").forEach(observeRevealElement);
  }
}

export function revealElements() {
  if (typeof document === "undefined") {
    return () => {};
  }

  scanForRevealElements(document);

  if (!revealMutationObserver && "MutationObserver" in window) {
    revealMutationObserver = new MutationObserver((mutations) => {
      mutations.forEach((mutation) => {
        mutation.addedNodes.forEach((node) => {
          scanForRevealElements(node);
        });
      });
    });

    revealMutationObserver.observe(document.body, {
      childList: true,
      subtree: true,
    });
  }

  return () => {
    revealMutationObserver?.disconnect();
    revealMutationObserver = null;
    revealObserver?.disconnect();
    revealObserver = null;
  };
}
