import { useEffect, useState } from "react";
import PropTypes from "prop-types";
import { getResponsiveImageProps } from "../../../utils/responsiveImages";
import "./Slideshow.scss";

const SLIDESHOW_SIZES = "(min-width: 1200px) 28vw, (min-width: 768px) 42vw, 92vw";
const SLIDESHOW_WIDTHS = { sm: 640, lg: 960 };

const Slideshow = ({ images, title }) => {
  const [currentIndex, setCurrentIndex] = useState(0);

  if (!images.length) {
    return null;
  }

  const activeImage = images[currentIndex];
  const responsiveImageProps = getResponsiveImageProps(
    activeImage,
    SLIDESHOW_SIZES,
    SLIDESHOW_WIDTHS
  );

  useEffect(() => {
    const interval = setInterval(() => {
      setCurrentIndex((prev) => (prev + 1) % images.length);
    }, 3000);

    return () => clearInterval(interval);
  }, [images.length]);

  useEffect(() => {
    const nextIndex = (currentIndex + 1) % images.length;
    const nextImage = new Image();
    const nextImageProps = getResponsiveImageProps(
      images[nextIndex],
      SLIDESHOW_SIZES,
      SLIDESHOW_WIDTHS
    );

    if (nextImageProps.srcSet) {
      nextImage.srcset = nextImageProps.srcSet;
      nextImage.sizes = nextImageProps.sizes;
    }

    nextImage.src = images[nextIndex];
  }, [currentIndex, images]);

  const handleDotClick = (idx) => {
    setCurrentIndex(idx);
  };

  return (
    <div className="slideshow">
      <img
        key={`${title}-img-${currentIndex}`}
        src={activeImage}
        alt={`${title} - ${currentIndex + 1}`}
        className="slideshow__image slideshow__image--active"
        loading="lazy"
        decoding="async"
        {...responsiveImageProps}
      />
      <div className="slideshow__dots">
        {images.map((_, idx) => (
          <button
            key={`${title}-dot-${idx}`}
            type="button"
            className={`slideshow__dot ${idx === currentIndex ? "active" : ""}`}
            onClick={() => handleDotClick(idx)}
            aria-label={`Go to image ${idx + 1}`}
            aria-current={idx === currentIndex ? "true" : "false"}
          />
        ))}
      </div>
    </div>
  );
};

Slideshow.propTypes = {
  images: PropTypes.arrayOf(PropTypes.string).isRequired,
  title: PropTypes.string.isRequired,
};

export default Slideshow;
